<script lang="ts" setup>
const user = useUser()
const inputRef = useTemplateRef('inputRef')

const { isLoading, refresh: add } = usePromise(undefined, async () => {
  const input = inputRef.value
  const email = input?.value.trim()
  input?.setCustomValidity('')

  if (!input || !email || !input.checkValidity())
    return

  if (user.blacklist.includes(email)) {
    input.setCustomValidity('Email already exists')
    input.reportValidity()

    return
  }

  await user.toggleBlacklist(email)
  input.value = ''
})
</script>

<template>
  <section>
    <h5 class="mb-3 text-13px text-neutral/80">
      Add Emails you want Auto Gmail to ignore
    </h5>

    <div
      :inert="isLoading"
      class="p-4 grow flex flex-col relative rounded-md border-1 border-neutral/8 overflow-hidden [&[inert]]:opacity-70"
    >
      <form class="mb-3 gap-2 flex-center" @submit.prevent="add">
        <input
          ref="inputRef"
          type="email"
          placeholder="Enter contact to block here..."
          class="w-full h-32px px-3 rounded bg-hex-fafafa outline-none border-1 border-solid border-black/5 focus-border-neutral/25 text-13px text-neutral placeholder:text-neutral/60"
          @input="inputRef?.setCustomValidity('')"
        >

        <CTAButton variant="neutral" type="submit" :loading="isLoading">
          Add
        </CTAButton>
      </form>

      <div
        v-for="(email) in user.blacklist"
        :key="email"
        class="group h-36px py-1 flex items-center text-13px text-neutral/70 hover:px-3 hover:bg-#fafafa cursor-default"
      >
        {{ email }}

        <IconButton
          icon="i-mdi-close size-4 text-neutral/30 group-not-hover:hidden"
          class="ml-auto"
          @click="user.toggleBlacklist(email)"
        />
      </div>
    </div>
  </section>
</template>
